package com.abdurashidov.notesapp.viewmodelimport android.app.Applicationimport androidx.lifecycle.ViewModelimport androidx.lifecycle.ViewModelProviderimport androidx.lifecycle.viewmodel.CreationExtrasimport com.abdurashidov.notesapp.repository.NoteRepository@Suppress("UNCHECKED_CAST")class NoteViewModelProviderFactory(    private val application: Application,    private val  noteRepository: NoteRepository    ):ViewModelProvider.Factory {    override fun <T : ViewModel> create(modelClass: Class<T>, extras: CreationExtras): T {        return NoteViewModel(application, noteRepository) as T    }}